-- ============================================================
-- SMARTSHORE HCM — Database Schema + Seed Data
-- Run this in Supabase → SQL Editor
-- ============================================================

-- ── 1. CREATE TABLES (safe to re-run) ────────────────────────

CREATE TABLE IF NOT EXISTS employees (
  id             uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name           text NOT NULL,
  initials       text,
  role           text,
  dept           text DEFAULT 'Delivery',
  email          text,
  location       text DEFAULT 'India',
  capacity_hours integer DEFAULT 40,
  color          text DEFAULT '#6366f1',
  created_at     timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS projects (
  id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name        text NOT NULL,
  client      text,
  status      text DEFAULT 'active',
  color       text DEFAULT '#3b82f6',
  start_date  date,
  end_date    date,
  budget      numeric DEFAULT 0,
  phase       text DEFAULT 'Active',
  progress    integer DEFAULT 0,
  description text,
  created_at  timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS employee_skills (
  id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  employee_id uuid REFERENCES employees(id) ON DELETE CASCADE,
  skill_name  text NOT NULL,
  skill_level integer DEFAULT 1,
  skill_order integer DEFAULT 0
);

CREATE TABLE IF NOT EXISTS assignments (
  id           uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  employee_id  uuid REFERENCES employees(id) ON DELETE CASCADE,
  project_id   uuid REFERENCES projects(id) ON DELETE CASCADE,
  week_start   date NOT NULL,
  hours        numeric DEFAULT 0,
  actual_hours numeric DEFAULT 0
);

CREATE TABLE IF NOT EXISTS board_tasks (
  id           uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  title        text NOT NULL,
  project_id   uuid REFERENCES projects(id) ON DELETE SET NULL,
  project_name text,
  priority     text DEFAULT 'Medium',
  due_date     date,
  status       text DEFAULT 'todo',
  created_at   timestamptz DEFAULT now()
);

-- ── 2. ROW LEVEL SECURITY (allow authenticated users full access) ─

ALTER TABLE employees       ENABLE ROW LEVEL SECURITY;
ALTER TABLE projects        ENABLE ROW LEVEL SECURITY;
ALTER TABLE employee_skills ENABLE ROW LEVEL SECURITY;
ALTER TABLE assignments     ENABLE ROW LEVEL SECURITY;
ALTER TABLE board_tasks     ENABLE ROW LEVEL SECURITY;

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='employees'       AND policyname='auth_all') THEN
    CREATE POLICY auth_all ON employees       FOR ALL TO authenticated USING (true) WITH CHECK (true); END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='projects'        AND policyname='auth_all') THEN
    CREATE POLICY auth_all ON projects        FOR ALL TO authenticated USING (true) WITH CHECK (true); END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='employee_skills' AND policyname='auth_all') THEN
    CREATE POLICY auth_all ON employee_skills FOR ALL TO authenticated USING (true) WITH CHECK (true); END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='assignments'     AND policyname='auth_all') THEN
    CREATE POLICY auth_all ON assignments     FOR ALL TO authenticated USING (true) WITH CHECK (true); END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='board_tasks'     AND policyname='auth_all') THEN
    CREATE POLICY auth_all ON board_tasks     FOR ALL TO authenticated USING (true) WITH CHECK (true); END IF;
END $$;

-- ── 3. CLEAR EXISTING DATA (fresh seed) ──────────────────────

TRUNCATE assignments, employee_skills, board_tasks, employees, projects RESTART IDENTITY CASCADE;

